files.stripe_webhook_route.ts:
import { NextRequest, NextResponse } from "next/server";
import Stripe from "stripe";
import { createClient } from "@supabase/supabase-js";

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY!, { apiVersion: "2024-06-20" });
const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

export async function POST(request: NextRequest) {
  const body = await request.text();
  const sig  = request.headers.get("stripe-signature")!;

  let event: Stripe.Event;
  try {
    event = stripe.webhooks.constructEvent(body, sig, process.env.STRIPE_WEBHOOK_SECRET!);
  } catch {
    return NextResponse.json({ error: "Invalid signature" }, { status: 400 });
  }

  switch (event.type) {

    // ── SUBSCRIPTION: Premium aktivieren ──────────────────────
    case "checkout.session.completed": {
      const session = event.data.object as Stripe.Checkout.Session;
      const userId  = session.metadata?.user_id;

      if (userId && session.mode === "subscription") {
        const until = new Date();
        until.setMonth(until.getMonth() + 1);
        await supabase.from("profiles").update({
          is_premium:         true,
          premium_until:      until.toISOString(),
          stripe_customer_id: session.customer as string,
        }).eq("id", userId);
      }

      // ── PAYMENT: Escrow bezahlt ─────────────────────────────
      if (session.mode === "payment" && session.payment_intent) {
        const { data: escrow } = await supabase
          .from("escrow_transactions")
          .select("id, seller_id, buyer_id")
          .eq("stripe_pi_id", session.payment_intent as string)
          .single();

        if (escrow) {
          await supabase.from("escrow_transactions")
            .update({ status: "paid" })
            .eq("id", escrow.id);

          // Log
          await supabase.from("marketplace_transactions").insert({
            escrow_id:       escrow.id,
            event_type:      "payment_received",
            amount:          session.amount_total ? session.amount_total / 100 : 0,
            stripe_event_id: event.id,
          });
        }
      }
      break;
    }

    // ── PAYMENT INTENT: direkte Bestätigung ───────────────────
    case "payment_intent.succeeded": {
      const pi = event.data.object as Stripe.PaymentIntent;
      const { data: escrow } = await supabase
        .from("escrow_transactions")
        .select("id")
        .eq("stripe_pi_id", pi.id)
        .single();

      if (escrow) {
        await supabase.from("escrow_transactions")
          .update({ status: "paid" })
          .eq("id", escrow.id);
      }
      break;
    }

    // ── SUBSCRIPTION: Premium deaktivieren ────────────────────
    case "customer.subscription.deleted": {
      const sub = event.data.object as Stripe.Subscription;
      const { data: profile } = await supabase
        .from("profiles")
        .select("id")
        .eq("stripe_customer_id", sub.customer as string)
        .single();
      if (profile) {
        await supabase.from("profiles")
          .update({ is_premium: false })
          .eq("id", profile.id);
      }
      break;
    }

    // ── STRIPE CONNECT: Seller verifiziert ────────────────────
    case "account.updated": {
      const account = event.data.object as Stripe.Account;
      if (account.charges_enabled && account.payouts_enabled) {
        await supabase.from("seller_stats")
          .update({ is_verified: true })
          .eq("stripe_account_id", account.id);
      }
      break;
    }
  }

  return NextResponse.json({ received: true });
}

files.supabase_server.ts:
import { createServerClient } from "@supabase/ssr";
import { createClient as createAnonClient } from "@supabase/supabase-js";
import { cookies } from "next/headers";
import { NextRequest } from "next/server";

export async function createClient() {
  const cookieStore = await cookies();
  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll(); },
        setAll(c) {
          try { c.forEach(({name,value,options})=>cookieStore.set(name,value,options)); } catch {}
        },
      },
    }
  );
}

export async function createRouteClient(request?: NextRequest) {
  const cookieStore = await cookies();
  const client = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() { return cookieStore.getAll(); },
        setAll(c) {
          try { c.forEach(({name,value,options})=>cookieStore.set(name,value,options)); } catch {}
        },
      },
    }
  );
  if (request) {
    const auth = request.headers.get("Authorization");
    if (auth?.startsWith("Bearer ")) {
      const token = auth.slice(7);
      const { data: { user } } = await client.auth.getUser(token);
      if (user) {
        return createAnonClient(
          process.env.NEXT_PUBLIC_SUPABASE_URL!,
          process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
          { global: { headers: { Authorization: `Bearer ${token}` } } }
        );
      }
    }
  }
  return client;
}

